@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-2">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveLeftAsync" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveRightAsync" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public int ColumnIndex { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnStatusChanged { get; set; }

    private bool IsMoving;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    private bool CanMoveLeft => ColumnIndex > 0;
    private bool CanMoveRight => ColumnIndex < Statuses.Length - 1;

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async System.Threading.Tasks.Task MoveLeftAsync()
    {
        IsMoving = true;
        await OnStatusChanged.InvokeAsync((Task.Id, Statuses[ColumnIndex - 1]));
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task MoveRightAsync()
    {
        IsMoving = true;
        await OnStatusChanged.InvokeAsync((Task.Id, Statuses[ColumnIndex + 1]));
        IsMoving = false;
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Project Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        @for (int i = 0; i < columns.Length; i++)
        {
            var index = i;
            var columnTasks = FilteredTasks.Where(t => t.Status == columns[index]).ToList();
            <BoardColumn ColumnName="@columns[index]"
                         ColumnIndex="index"
                         Tasks="columnTasks"
                         OnStatusChanged="HandleStatusChangedAsync"
                         OnTaskCreated="HandleTaskCreatedAsync" />
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleStatusChangedAsync((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == args.TaskId);
            if (task is not null)
            {
                allTasks = allTasks.Select(t => t.Id == args.TaskId ? t with { Status = args.NewStatus } : t).ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreatedAsync((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // CreateTaskAsync may not set the status to the column's status, so adjust
            allTasks.Add(newTask with { Status = args.Status });
            if (args.Status != newTask.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, args.Status);
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

