{"file_text": "@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Project Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        @for (int i = 0; i < columns.Length; i++)
        {
            var index = i;
            var columnTasks = FilteredTasks.Where(t => t.Status == columns[index]).ToList();
            <BoardColumn ColumnName="@columns[index]"
                         ColumnIndex="index"
                         Tasks="columnTasks"
                         OnStatusChanged="HandleStatusChangedAsync"
                         OnTaskCreated="HandleTaskCreatedAsync" />
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchText)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleStatusChangedAsync((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            allTasks = allTasks
                .Select(t => t.Id == args.TaskId ? t with { Status = args.NewStatus } : t)
                .ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreatedAsync((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            if (newTask.Status != args.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, args.Status);
                newTask = newTask with { Status = args.Status };
            }
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}
